package com.phuong.services.impl;

import com.phuong.modal.Genre;
import com.phuong.reponsitory.GenreReponsitory;
import com.phuong.services.GenreService;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;


@Service
@RequiredArgsConstructor
public class GenreServiceImpl implements GenreService {

    @Autowired
    private final GenreReponsitory genereRepository;

    @Override
    public Genre createGenre(Genre genre) {
        return genereRepository.save(genre);
    }
}

package com.phuong.services.impl;

import com.phuong.modal.Genre;
import com.phuong.repository.GenreRepository;
import com.phuong.services.GenreService;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;


@Service
@RequiredArgsConstructor
public class GenreServiceImpl implements GenreService {

    @Autowired
    private final GenreRepository genreRepository;

    @Override
    public Genre createGenre(Genre genre) {
        return genreRepository.save(genre);
    }
}
